[DataContractAttribute]
public class MyContract
{

    // Private member variables
    str companyId;
    str messageQueue;
    str messageType;
    str messageContent;
    str messageId;
    str myKey;
    utcdatetime timestamp;
    str eventType;
    str payload;


}

Method.Source:
[DataMemberAttribute]
public str parmMyKey(str _myKey = myKey)
{
    myKey = _myKey;
    return myKey;
}

[DataMemberAttribute]
public str parmMessageId(str _messageId = messageId)
{
    messageId = _messageId;
    return messageId;
}

[DataMemberAttribute]
public str parmMessageContent(str _messageContent = messageContent)
{
    messageContent = _messageContent;
    return messageContent;
}

[DataMemberAttribute]
public str parmMessageType(str _messageType = messageType)
{
    messageType = _messageType;
    return messageType;
}

[DataMemberAttribute]
public str parmMessageQueue(str _messageQueue = messageQueue)
{
    messageQueue = _messageQueue;
    return messageQueue;
}

[DataMemberAttribute]
public str parmCompanyId(str _companyId = companyId)
{
    companyId = _companyId;
    return companyId;
}

// Parm method for timestamp
[DataMemberAttribute]
public utcdatetime parmTimestamp(utcdatetime _timestamp = timestamp)
{
    timestamp = _timestamp;
    return timestamp;
}

// Parm method for eventType

[DataMemberAttribute]
public str parmEventType(str _eventType = eventType)
{
    eventType = _eventType;
    return eventType;
}

// Parm method for payload
[DataMemberAttribute]
public str parmPayload(str _payload = payload)
{
    payload = _payload;
    return payload;
}
